import{c as a,Q as s,j as n,m as t}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Authentication Flow","description":"","frontmatter":{},"headers":[],"relativePath":"authentication.md","filePath":"authentication.md","lastUpdated":1778829398000}'),o={name:"authentication.md"};function i(l,e,d,c,p,r){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="authentication-flow" tabindex="-1">Authentication Flow <a class="header-anchor" href="#authentication-flow" aria-label="Permalink to &quot;Authentication Flow&quot;">​</a></h1><p>This document covers how authentication works across the Exto platform — Console, exto-web, and Zitadel.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Console acts as the <strong>centralized login gateway</strong> for the entire platform. Both Console&#39;s own UI and exto-web (the instance tenant app) route through Console&#39;s login page for authentication. Zitadel is the identity provider that handles the actual credential verification.</p><table tabindex="0"><thead><tr><th>Component</th><th>Role</th></tr></thead><tbody><tr><td><strong>Console</strong></td><td>Login gateway — org resolution, IdP selection, branding</td></tr><tr><td><strong>Zitadel</strong></td><td>Identity provider — credential verification, SSO, MFA, token issuer</td></tr><tr><td><strong>exto-web</strong></td><td>Tenant application — initiates login via Console, exchanges tokens directly with Zitadel</td></tr><tr><td><strong>exto-go</strong></td><td>exto-web backend — validates JWT, manages sessions</td></tr></tbody></table><hr><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><h3 id="separate-oidc-apps" tabindex="-1">Separate OIDC Apps <a class="header-anchor" href="#separate-oidc-apps" aria-label="Permalink to &quot;Separate OIDC Apps&quot;">​</a></h3><p>Each application has its own OIDC app registered in Zitadel:</p><table tabindex="0"><thead><tr><th>OIDC App</th><th>Client ID Source</th><th>Redirect URIs</th></tr></thead><tbody><tr><td><strong>Console Portal</strong></td><td><code>VITE_CONSOLE_PORTAL_CLIENT_ID</code> env var</td><td><code>console.example.com/callback</code></td></tr><tr><td><strong>Instance</strong> (per instance)</td><td>Created by Console via <code>CreateInstanceOIDCApp</code></td><td><code>instance.example.com/auth/callback</code> and <code>instance.example.com/3/auth/callback</code></td></tr></tbody></table><blockquote><p><strong>Note:</strong> Each instance OIDC app registers <strong>two</strong> redirect URIs — <code>/auth/callback</code> (standard) and <code>/3/auth/callback</code> (v3 app route). Both are registered in Zitadel when the instance is created. Console&#39;s login resolver accepts either path during client validation.</p></blockquote><p>Zitadel routes the callback to the correct app based on the <code>client_id</code> in the authorize request.</p><h3 id="orgs-and-oidc-apps-are-independent" tabindex="-1">Orgs and OIDC Apps Are Independent <a class="header-anchor" href="#orgs-and-oidc-apps-are-independent" aria-label="Permalink to &quot;Orgs and OIDC Apps Are Independent&quot;">​</a></h3><ul><li><strong>Org</strong> = where the user lives (login policies, IdPs, password rules)</li><li><strong>OIDC App</strong> = which application is requesting auth (redirect URIs, client credentials)</li></ul><p>A user in any org can authenticate against any OIDC app. The org scope (<code>urn:zitadel:iam:org:id:{orgId}</code>) tells Zitadel which org&#39;s policies to apply.</p><hr><h2 id="flow-1-console-login-internal-admin-or-customer-accessing-console" tabindex="-1">Flow 1: Console Login (Internal Admin or Customer accessing Console) <a class="header-anchor" href="#flow-1-console-login-internal-admin-or-customer-accessing-console" aria-label="Permalink to &quot;Flow 1: Console Login (Internal Admin or Customer accessing Console)&quot;">​</a></h2><p>Used when a user navigates directly to Console to manage customers, billing, settings, etc.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User → Console login page (/)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Enter email</span></span>
<span class="line"><span>  ├─ POST /api/v1/login/resolve-org  →  { type, orgs, authMethods }</span></span>
<span class="line"><span>  │     ├─ &quot;internal&quot;  → redirect to Zitadel (no org scope)</span></span>
<span class="line"><span>  │     └─ &quot;customer&quot;  → pick org → pick auth method (SSO / password)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Console generates PKCE (code_verifier + code_challenge)</span></span>
<span class="line"><span>  ├─ Stores code_verifier, state, and nonce in sessionStorage</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └─ Redirect to Zitadel:</span></span>
<span class="line"><span>       GET {issuer}/oauth/v2/authorize</span></span>
<span class="line"><span>         ?client_id={CONSOLE_PORTAL_CLIENT_ID}</span></span>
<span class="line"><span>         &amp;redirect_uri={console}/callback</span></span>
<span class="line"><span>         &amp;scope=openid profile email urn:zitadel:iam:user:resourceowner</span></span>
<span class="line"><span>                [urn:zitadel:iam:org:id:{orgId}]</span></span>
<span class="line"><span>                [urn:zitadel:iam:org:idp:id:{idpId}]</span></span>
<span class="line"><span>         &amp;code_challenge={challenge}</span></span>
<span class="line"><span>         &amp;code_challenge_method=S256</span></span>
<span class="line"><span>         &amp;state={state}</span></span>
<span class="line"><span>         &amp;nonce={nonce}</span></span>
<span class="line"><span>         &amp;login_hint={email}</span></span></code></pre></div><p>After Zitadel authenticates the user:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Zitadel → Console /callback?code={code}&amp;state={state}</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Validate state matches sessionStorage</span></span>
<span class="line"><span>  ├─ Exchange code for tokens:</span></span>
<span class="line"><span>  │     POST {issuer}/oauth/v2/token</span></span>
<span class="line"><span>  │       grant_type=authorization_code</span></span>
<span class="line"><span>  │       code={code}</span></span>
<span class="line"><span>  │       code_verifier={verifier}</span></span>
<span class="line"><span>  │       client_id={CONSOLE_PORTAL_CLIENT_ID}</span></span>
<span class="line"><span>  │       redirect_uri={console}/callback</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Validate nonce in id_token matches sessionStorage</span></span>
<span class="line"><span>  ├─ Decode JWT → extract user info (sub, email, org, role)</span></span>
<span class="line"><span>  ├─ GET /api/v1/auth/me → DB-resolved role + customerId</span></span>
<span class="line"><span>  └─ Navigate to dashboard or customer portal</span></span></code></pre></div><hr><h2 id="flow-2-exto-web-login-via-console-gateway" tabindex="-1">Flow 2: exto-web Login via Console Gateway <a class="header-anchor" href="#flow-2-exto-web-login-via-console-gateway" aria-label="Permalink to &quot;Flow 2: exto-web Login via Console Gateway&quot;">​</a></h2><p>Used when a tenant user logs into exto-web. Console acts as a transparent login gateway — it never touches the tokens.</p><h3 id="step-1-exto-web-redirects-to-console" tabindex="-1">Step 1: exto-web redirects to Console <a class="header-anchor" href="#step-1-exto-web-redirects-to-console" aria-label="Permalink to &quot;Step 1: exto-web redirects to Console&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User clicks &quot;SSO&quot; on exto-web login page</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ exto-web generates PKCE (code_verifier + code_challenge)</span></span>
<span class="line"><span>  ├─ Stores code_verifier, state, and nonce in sessionStorage</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └─ Redirect to Console login page:</span></span>
<span class="line"><span>       GET {consoleLoginUrl}/</span></span>
<span class="line"><span>         ?client_id={INSTANCE_OIDC_CLIENT_ID}</span></span>
<span class="line"><span>         &amp;redirect_uri={exto-web}/auth/callback</span></span>
<span class="line"><span>         &amp;scope=openid profile email offline_access</span></span>
<span class="line"><span>         &amp;code_challenge={challenge}</span></span>
<span class="line"><span>         &amp;code_challenge_method=S256</span></span>
<span class="line"><span>         &amp;state={state}</span></span>
<span class="line"><span>         &amp;nonce={nonce}</span></span></code></pre></div><blockquote><p><strong>Note:</strong> exto-web sends standard OIDC scopes only. It must NOT send Zitadel-specific scopes (<code>urn:zitadel:iam:*</code>). Console owns org/IdP scope resolution and will strip any such scopes from external requests (see <a href="#scope-sanitization">Scope Sanitization</a>).</p></blockquote><h3 id="step-2-console-validates-and-shows-login-ui" tabindex="-1">Step 2: Console validates and shows login UI <a class="header-anchor" href="#step-2-console-validates-and-shows-login-ui" aria-label="Permalink to &quot;Step 2: Console validates and shows login UI&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Console login page loads</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Detects external OIDC params (client_id, redirect_uri, etc.)</span></span>
<span class="line"><span>  ├─ Validates via: GET /api/v1/login/resolve-client</span></span>
<span class="line"><span>  │     ?client_id={INSTANCE_OIDC_CLIENT_ID}</span></span>
<span class="line"><span>  │     &amp;redirect_uri={exto-web}/auth/callback</span></span>
<span class="line"><span>  │   → Checks client_id exists in instance_connections</span></span>
<span class="line"><span>  │   → Checks redirect_uri matches registered URI</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ User enters email</span></span>
<span class="line"><span>  ├─ POST /api/v1/login/resolve-org → org + auth methods</span></span>
<span class="line"><span>  └─ User selects org / auth method</span></span></code></pre></div><h3 id="step-3-console-sanitizes-scopes-and-redirects-to-zitadel" tabindex="-1">Step 3: Console sanitizes scopes and redirects to Zitadel <a class="header-anchor" href="#step-3-console-sanitizes-scopes-and-redirects-to-zitadel" aria-label="Permalink to &quot;Step 3: Console sanitizes scopes and redirects to Zitadel&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Console builds Zitadel authorize URL:</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Sanitize external scope: strip all urn:zitadel:iam:* scopes from exto-web&#39;s request</span></span>
<span class="line"><span>  ├─ Append Console-resolved scopes:</span></span>
<span class="line"><span>  │     urn:zitadel:iam:org:id:{orgId}       ← from /resolve-org</span></span>
<span class="line"><span>  │     urn:zitadel:iam:org:idp:id:{idpId}   ← from /resolve-org (if SSO)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └─ Redirect to Zitadel:</span></span>
<span class="line"><span>       GET {issuer}/oauth/v2/authorize</span></span>
<span class="line"><span>         ?response_type=code</span></span>
<span class="line"><span>         &amp;client_id={INSTANCE_OIDC_CLIENT_ID}    ← exto-web&#39;s client ID</span></span>
<span class="line"><span>         &amp;redirect_uri={exto-web}/auth/callback   ← exto-web&#39;s callback</span></span>
<span class="line"><span>         &amp;scope={sanitized scopes}                 ← see Scope Sanitization below</span></span>
<span class="line"><span>                [urn:zitadel:iam:org:id:{orgId}]</span></span>
<span class="line"><span>                [urn:zitadel:iam:org:idp:id:{idpId}]</span></span>
<span class="line"><span>         &amp;code_challenge={challenge}               ← exto-web&#39;s PKCE challenge</span></span>
<span class="line"><span>         &amp;code_challenge_method=S256</span></span>
<span class="line"><span>         &amp;state={state}                            ← exto-web&#39;s state</span></span>
<span class="line"><span>         &amp;nonce={nonce}                            ← exto-web&#39;s nonce (passed through)</span></span>
<span class="line"><span>         &amp;login_hint={email}</span></span></code></pre></div><h3 id="step-4-zitadel-redirects-directly-to-exto-web" tabindex="-1">Step 4: Zitadel redirects directly to exto-web <a class="header-anchor" href="#step-4-zitadel-redirects-directly-to-exto-web" aria-label="Permalink to &quot;Step 4: Zitadel redirects directly to exto-web&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Zitadel authenticates user → redirects to exto-web:</span></span>
<span class="line"><span>  GET {exto-web}/auth/callback?code={code}&amp;state={state}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Console is NOT involved from this point forward.</span></span></code></pre></div><h3 id="step-5-exto-web-exchanges-code-for-tokens" tabindex="-1">Step 5: exto-web exchanges code for tokens <a class="header-anchor" href="#step-5-exto-web-exchanges-code-for-tokens" aria-label="Permalink to &quot;Step 5: exto-web exchanges code for tokens&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>exto-web /auth/callback</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Validate state matches sessionStorage</span></span>
<span class="line"><span>  ├─ Exchange code directly with Zitadel:</span></span>
<span class="line"><span>  │     POST {issuer}/oauth/v2/token</span></span>
<span class="line"><span>  │       grant_type=authorization_code</span></span>
<span class="line"><span>  │       code={code}</span></span>
<span class="line"><span>  │       code_verifier={verifier}    ← from exto-web&#39;s sessionStorage</span></span>
<span class="line"><span>  │       client_id={INSTANCE_OIDC_CLIENT_ID}</span></span>
<span class="line"><span>  │       redirect_uri={exto-web}/auth/callback</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ Validate nonce in id_token matches sessionStorage</span></span>
<span class="line"><span>  ├─ Store tokens in sessionStorage</span></span>
<span class="line"><span>  ├─ POST /auth/zitadel/callback → exto-go validates JWT, creates session</span></span>
<span class="line"><span>  └─ Navigate to /projects</span></span></code></pre></div><hr><h2 id="flow-comparison" tabindex="-1">Flow Comparison <a class="header-anchor" href="#flow-comparison" aria-label="Permalink to &quot;Flow Comparison&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Console login:       Console → Zitadel → Console/callback → Console exchanges code → Console dashboard</span></span>
<span class="line"><span>exto-web login:  exto-web → Console (UI only) → Zitadel → exto-web/callback → exto-web exchanges code</span></span></code></pre></div><p>Key difference: In the exto-web flow, Console <strong>only provides the login UI</strong>. It passes exto-web&#39;s OIDC params through to Zitadel. The token exchange happens directly between exto-web and Zitadel.</p><hr><h2 id="org-resolution" tabindex="-1">Org Resolution <a class="header-anchor" href="#org-resolution" aria-label="Permalink to &quot;Org Resolution&quot;">​</a></h2><p>The <code>/api/v1/login/resolve-org</code> endpoint determines the user&#39;s org and available auth methods.</p><p><strong>Request:</strong></p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">POST /api/v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/login/resolve-org</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user@company.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p><strong>Response types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Meaning</th><th>Next step</th></tr></thead><tbody><tr><td><code>internal</code></td><td>User is an internal Exto admin</td><td>Console flow: redirect to Zitadel (no org scope). exto-web flow: show generic error (admins don&#39;t use exto-web)</td></tr><tr><td><code>customer</code></td><td>User belongs to one or more customer orgs</td><td>Pick org → pick auth method → redirect</td></tr><tr><td><code>not_found</code></td><td>No account for this email</td><td>Show generic error (same message as <code>internal</code> in exto-web flow to prevent email enumeration)</td></tr></tbody></table><p><strong>Auth methods per org:</strong></p><table tabindex="0"><thead><tr><th>Method</th><th>Behavior</th></tr></thead><tbody><tr><td><code>password</code></td><td>Redirect to Zitadel with <code>login_hint</code> (Zitadel shows password form)</td></tr><tr><td><code>sso</code></td><td>Redirect to Zitadel with <code>idpId</code> scope (auto-redirect to IdP)</td></tr></tbody></table><hr><h2 id="client-validation" tabindex="-1">Client Validation <a class="header-anchor" href="#client-validation" aria-label="Permalink to &quot;Client Validation&quot;">​</a></h2><p>The <code>/api/v1/login/resolve-client</code> endpoint validates external OIDC params in the exto-web flow.</p><p><strong>Request:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/v1/login/resolve-client?client_id={id}&amp;redirect_uri={uri}</span></span></code></pre></div><p><strong>Validation:</strong></p><ol><li>Look up <code>client_id</code> in <code>instance_connections</code> collection</li><li>Reject if <code>oidcRedirectUri</code> is empty (legacy records created before this field was introduced)</li><li>Verify <code>redirect_uri</code> matches the registered <code>oidcRedirectUri</code></li><li>Return <code>{ valid: true }</code> or <code>{ valid: false }</code></li></ol><p>This prevents open redirect attacks — Console will not construct a Zitadel authorize URL with an unregistered or missing redirect URI.</p><hr><h2 id="scope-sanitization" tabindex="-1">Scope Sanitization <a class="header-anchor" href="#scope-sanitization" aria-label="Permalink to &quot;Scope Sanitization&quot;">​</a></h2><p>In the exto-web flow, <strong>Console owns all Zitadel-specific scopes</strong>. External callers (exto-web) send standard OIDC scopes (<code>openid</code>, <code>profile</code>, <code>email</code>, <code>offline_access</code>), and Console appends the org/IdP scopes it resolved via <code>/resolve-org</code>.</p><p><strong>Why?</strong> Org and IdP scopes determine which org&#39;s login policies apply and whether to auto-redirect to an external IdP. Trusting these from an external caller would allow scope injection — e.g., forcing a different org&#39;s policies or bypassing IdP selection.</p><p><strong>How it works:</strong></p><ol><li>Console receives exto-web&#39;s scope string (e.g., <code>openid profile email offline_access</code>)</li><li>Console strips any scope starting with <code>urn:zitadel:iam:</code> — these are never trusted from external callers</li><li>Console appends its own resolved scopes: <ul><li><code>urn:zitadel:iam:org:id:{orgId}</code> — resolved via <code>/resolve-org</code></li><li><code>urn:zitadel:iam:org:idp:id:{idpId}</code> — resolved via <code>/resolve-org</code> (only for SSO methods)</li></ul></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>External scope:   &quot;openid profile email offline_access urn:zitadel:iam:org:id:fake123&quot;</span></span>
<span class="line"><span>                                                        ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^</span></span>
<span class="line"><span>                                                        stripped by Console</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sanitized scope:  &quot;openid profile email offline_access&quot;</span></span>
<span class="line"><span>Final scope:      &quot;openid profile email offline_access urn:zitadel:iam:org:id:{resolved_orgId}&quot;</span></span></code></pre></div><blockquote><p>Console&#39;s own login flow (Flow 1) is not affected — it builds scopes entirely from <code>buildScope()</code> using its own OIDC config.</p></blockquote><hr><h2 id="idp-auto-redirect" tabindex="-1">IdP Auto-Redirect <a class="header-anchor" href="#idp-auto-redirect" aria-label="Permalink to &quot;IdP Auto-Redirect&quot;">​</a></h2><p>When a customer org has a single SSO provider and the auth rule is SSO-only, Console passes the IdP scope:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>scope=... urn:zitadel:iam:org:idp:id:{idpId}</span></span></code></pre></div><p>This causes Zitadel to <strong>skip its own login page</strong> entirely and redirect directly to the external IdP (Google, Azure, etc.). The user never sees Zitadel&#39;s UI.</p><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="console-web-env" tabindex="-1">Console (web/.env) <a class="header-anchor" href="#console-web-env" aria-label="Permalink to &quot;Console (web/.env)&quot;">​</a></h3><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VITE_ZITADEL_ISSUER=https://auth.exto360.com</span></span>
<span class="line"><span>VITE_CONSOLE_PORTAL_CLIENT_ID=&lt;console-oidc-client-id&gt;</span></span>
<span class="line"><span>VITE_REDIRECT_URI=https://console.exto360.com/callback</span></span>
<span class="line"><span>VITE_ZITADEL_ADMIN_ORG_ID=&lt;admin-org-id&gt;</span></span></code></pre></div><h3 id="exto-go-env" tabindex="-1">exto-go (.env) <a class="header-anchor" href="#exto-go-env" aria-label="Permalink to &quot;exto-go (.env)&quot;">​</a></h3><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ZITADEL_ISSUER=https://auth.exto360.com</span></span>
<span class="line"><span>ZITADEL_CLIENT_ID=&lt;instance-oidc-client-id&gt;</span></span>
<span class="line"><span>CONSOLE_LOGIN_URL=https://console.exto360.com</span></span></code></pre></div><p>The <code>CONSOLE_LOGIN_URL</code> is returned via the <code>/auth/config</code> endpoint so exto-web knows where to redirect for login.</p><h3 id="instance-connection-stored-in-postgresql-by-console" tabindex="-1">Instance Connection (stored in PostgreSQL by Console) <a class="header-anchor" href="#instance-connection-stored-in-postgresql-by-console" aria-label="Permalink to &quot;Instance Connection (stored in PostgreSQL by Console)&quot;">​</a></h3><p>Each instance has an <code>instance_connections</code> record with:</p><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th></tr></thead><tbody><tr><td><code>oidcClientId</code></td><td>Instance&#39;s Zitadel OIDC client ID</td></tr><tr><td><code>oidcRedirectUri</code></td><td>Registered redirect URI for validation</td></tr><tr><td><code>zitadelAppId</code></td><td>Zitadel app ID (for rotation/deletion)</td></tr></tbody></table><hr><h2 id="frontend-architecture-console" tabindex="-1">Frontend Architecture (Console) <a class="header-anchor" href="#frontend-architecture-console" aria-label="Permalink to &quot;Frontend Architecture (Console)&quot;">​</a></h2><p>The Console frontend separates the two login flows into independent components and functions to avoid entanglement.</p><h3 id="page-components" tabindex="-1">Page Components <a class="header-anchor" href="#page-components" aria-label="Permalink to &quot;Page Components&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>File</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>LoginLanding</code></td><td><code>pages/LoginLanding.tsx</code></td><td>Thin dispatcher — parses URL for external OIDC params, renders <code>ConsoleLoginPage</code> or <code>ExternalLoginPage</code></td></tr><tr><td><code>ConsoleLoginPage</code></td><td><code>pages/login/ConsoleLoginPage.tsx</code></td><td>Console&#39;s own login flow — resolves org, calls <code>redirectConsoleLogin()</code></td></tr><tr><td><code>ExternalLoginPage</code></td><td><code>pages/login/ExternalLoginPage.tsx</code></td><td>exto-web gateway flow — validates client, resolves org, calls <code>redirectExternalToZitadel()</code></td></tr><tr><td><code>LoginShell</code></td><td><code>pages/login/LoginShell.tsx</code></td><td>Shared UI building blocks (<code>LoginLayout</code>, <code>EmailStep</code>, <code>OrgPickerStep</code>, <code>IdpPickerStep</code>, <code>ErrorBanner</code>)</td></tr><tr><td><code>CallbackPage</code></td><td><code>auth/CallbackPage.tsx</code></td><td>Console&#39;s own OIDC callback — exchanges code, validates nonce, hydrates session</td></tr></tbody></table><h3 id="auth-functions" tabindex="-1">Auth Functions <a class="header-anchor" href="#auth-functions" aria-label="Permalink to &quot;Auth Functions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Function</th><th>File</th><th>Flow</th></tr></thead><tbody><tr><td><code>redirectConsoleLogin(opts?)</code></td><td><code>auth/login.ts</code></td><td>Console&#39;s own flow — generates PKCE + nonce, stores in sessionStorage, redirects to Zitadel</td></tr><tr><td><code>redirectExternalToZitadel(externalParams, opts?)</code></td><td><code>auth/login.ts</code></td><td>External flow — sanitizes scopes, passes through external PKCE/state/nonce, redirects to Zitadel</td></tr><tr><td><code>sanitizeExternalScope(rawScope, orgId?, idpId?)</code></td><td><code>auth/login.ts</code></td><td>Strips <code>urn:zitadel:iam:*</code> scopes, appends Console-resolved org/IdP scopes</td></tr><tr><td><code>silentReauth()</code></td><td><code>auth/login.ts</code></td><td>Console-only — silent re-auth via <code>prompt=none</code></td></tr></tbody></table><h3 id="flow-isolation" tabindex="-1">Flow Isolation <a class="header-anchor" href="#flow-isolation" aria-label="Permalink to &quot;Flow Isolation&quot;">​</a></h3><p>The two flows are fully separated:</p><ul><li><strong>Console login</strong>: <code>ConsoleLoginPage</code> → <code>redirectConsoleLogin()</code> → Zitadel → <code>CallbackPage</code></li><li><strong>External login</strong>: <code>ExternalLoginPage</code> → <code>redirectExternalToZitadel()</code> → Zitadel → exto-web callback</li></ul><p>They share only the visual UI components from <code>LoginShell</code> (email form, org picker, IdP picker). There is no <code>if (externalParams)</code> branching in the redirect or page logic — each flow has its own dedicated function and component.</p><h3 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h3><p>Unit tests are in <code>web/src/auth/__tests__/</code> and cover:</p><ul><li><code>pkce.test.ts</code> — PKCE verifier/challenge generation, auth URL construction</li><li><code>jwt.test.ts</code> — JWT payload decoding edge cases</li><li><code>login.test.ts</code> — scope sanitization (injection prevention), external redirect param forwarding, nonce/login_hint passthrough</li></ul><p>Run with <code>npm test</code> from the <code>web/</code> directory.</p><hr><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><ul><li><strong>PKCE (S256)</strong> is used for all flows — no client secrets on the frontend.</li><li><strong>Nonce</strong> is included in the authorize request and validated in the <code>id_token</code> on callback. This prevents token replay attacks. Each app (Console, exto-web) generates and validates its own nonce. Console passes through exto-web&#39;s nonce to Zitadel without storing it.</li><li><strong>Console never touches tokens</strong> in the exto-web flow. It only provides the login UI and constructs the Zitadel authorize URL.</li><li><strong>Redirect URI validation</strong> prevents open redirect attacks. Console validates the <code>redirect_uri</code> against the registered URI in <code>instance_connections</code> before proceeding. Connections with an empty <code>oidcRedirectUri</code> are rejected.</li><li><strong>State parameter</strong> prevents CSRF. Generated by the initiating app (Console or exto-web), validated on callback.</li><li><strong>Org scope</strong> ensures Zitadel applies the correct org&#39;s login policies (MFA, password rules, allowed IdPs).</li><li><strong>Scope sanitization</strong> prevents scope injection. Console strips all <code>urn:zitadel:iam:*</code> scopes from external requests and only adds the scopes it resolved itself via <code>/resolve-org</code>. This ensures an external caller cannot force a different org&#39;s policies or bypass IdP selection.</li><li><strong>Anti-enumeration</strong>: The <code>/resolve-org</code> endpoint returns <code>internal</code> for real admins and <code>not_found</code> for unknown emails. The frontend shows the same generic error for both in the exto-web flow, and for <code>not_found</code> in Console&#39;s own flow. This prevents attackers from determining whether an email has an account.</li></ul>`,98)])])}const u=a(o,[["render",i]]);export{g as __pageData,u as default};
